199→        return(
200→            <div className='notification-loading-container'>
201→                No notifications availabe
202→            </div>
203→        )
204→    }
205→
206→    if(isLoading){
207→        return(
208→            <div className="notification-loading-container">
209→                <MoonLoader size={25} color="var(--loader-color)" loading={isLoading}/>
210→            </div>
211→        )
212→    }
213→
214→    return(
215→        <>
216→        <div ref={scrollToTop}/>
217→        <div className="notifications-container">
218→            {notifications?.map((notification) => {
219→                const isOpinion = notification?.source === 'opinion';
220→                const displayType = isOpinion ? 'opinion_reply' : notification?.type;
221→                const parsedContent = !isOpinion ? ParseContent(notification?.journals?.content) : null;
222→
223→                return(
224→                <div key={`${notification.source}-${notification.id}`} className={notification?.read ? "notification-cards" : "notification-cards-unread"}>
225→
226→                    <div className="notification-cards-child-container">
227→
228→                        <div className="notification-icon-container">
229→                            {iconArray.map((icon, index) => (
230→                                <div className="notification-icon" key={index}>
231→                                    {icon.type === displayType ? icon.icon : null}
232→                                </div>
233→                            ))}
234→                        </div>
235→
236→                        <div className="notification-contents-container">
237→
238→                            <div className="notification-sender-user-metadata">
239→                                <div className="notification-sender-user-metadata-child">
240→                                    <div className={`notif-sender-profilepic-container ${notification?.users?.badge === 'legend' ? 'notif-avatar-ring-legend' : notification?.users?.badge === 'og' ? 'notif-avatar-ring-og' : ''}`}>
241→                                        <img loading="lazy" className="notif-sender-profilepic" src={notification?.users?.image_url || '/assets/profile.jpg'} alt="notificataion sender profile picture" />
242→                                    </div>
243→
244→                                    <div className="notif-sender-name-container">
245→                                        <p className="notif-sender-name">{notification?.users?.name}</p>
246→                                        <VerifiedBadge badge={notification?.users?.badge} size={14} />
247→                                        <p className="notif-type">{FormatNotificationType(displayType)}</p>
248→                                    </div>
249→
250→                                    <div className="notification-date-container">
