252→                                    </div>
253→                                </div>
254→                                <div className="notification-settings">
255→                                    {settingsId === notification.id && (
256→                                        <AnimatePresence>
257→                                        <motion.div
258→                                        initial={{opacity: 0, scale: 0}}
259→                                        animate={{opacity: 1, scale: 1, transition:{type: 'spring', stiffness: 300, damping: 25, mass: 0.8}}}
260→                                        exit={{ opacity: 0, scale: 0,
261→                                            transition: {
