let _lastHottestCheckTime = 0;
const HOTTEST_CHECK_INTERVAL_MS = 5 * 60 * 1000;

const updateHottestTrackerIfChanged = async (monthKey, topPost) => {
    const now = Date.now();
    if(now - _lastHottestCheckTime < HOTTEST_CHECK_INTERVAL_MS){
        return;
    }
    _lastHottestCheckTime = now;

    const newJournalId = topPost.id;
    const newUserId = topPost.users?.id || topPost.user_id;
    const newHotScore = topPost.hot_score || 0;

    const {data: existing, error: selectError} = await supabase
        .from('hottest_tracker')
        .select('*')
        .eq('month_key', monthKey)
        .maybeSingle();

    if(selectError){
        console.error('hottest tracker select error:', selectError.message);
        return;
    }

    if(existing && existing.journal_id === newJournalId){
        return;
    }

    // Notify old #1 that they've been replaced
    if(existing){
        await supabase
            .from('notifications')
            .insert({
                sender_id: existing.user_id,
                receiver_id: existing.user_id,
                journal_id: existing.journal_id,
                type: 'hottest_post_replaced',
                read: false,
            });
    }

    // Upsert new #1
    const {error: upsertError} = await supabase
        .from('hottest_tracker')
        .upsert({
            month_key: monthKey,
            journal_id: newJournalId,
            user_id: newUserId,
            hot_score: newHotScore,
            updated_at: new Date().toISOString(),
        }, {onConflict: 'month_key'});

    if(upsertError){
        console.error('hottest tracker upsert error:', upsertError.message);
        return;
    }

    // Notify new #1
    await supabase
        .from('notifications')
        .insert({
            sender_id: newUserId,
            receiver_id: newUserId,
            journal_id: newJournalId,
            type: 'hottest_post',
            read: false,
        });
}

