    const paresedLimit = parseInt(limit);
    let query = supabase
    .from('bookmarks')
    .select(`id, created_at, journal_id,
        journals(
        id, created_at, user_id, content, title, 
        comment_count: comments(count),
        bookmark_count: bookmarks(count),

