 634→        const result = await getUserByUsernameService(username);
 635→        const user = result?.userData?.[0];
 636→        if (!user) {
 637→            return res.redirect(302, DEFAULT_OG_IMAGE_URL);
 638→        }
 639→
 640→        const displayName = normalizeWhitespace(user.name) || username;
 641→        const handle = `@${normalizeWhitespace(user.username || username)}`;
 642→        const bio = toPreviewText(user.bio || '', 120);
 643→
 644→        // ── Fetch background image ──
 645→        let bgBuffer = null;
 646→        const bgStyle = user.background || {};
 647→        const bgImageMatch = typeof bgStyle.backgroundImage === 'string'
 648→            ? bgStyle.backgroundImage.match(/url\(["']?([^"')]+)["']?\)/)
 649→            : null;
 650→        const bgImageUrl = bgImageMatch?.[1];
 651→
 652→        if (bgImageUrl) {
 653→            const bgEval = evaluateShareImageCandidate(bgImageUrl);
 654→            if (bgEval.ok && bgEval.resolvedUrl) {
 655→                try {
 656→                    const remote = await fetchRemoteImageBuffer(bgEval.resolvedUrl);
 657→                    bgBuffer = remote.buffer;
 658→                } catch { /* use fallback gradient */ }
 659→            }
 660→        }
 661→
 662→        // ── Base layer: background or dark gradient ──
 663→        let baseLayer;
 664→        if (bgBuffer) {
 665→            baseLayer = await sharp(bgBuffer, { limitInputPixels: 60_000_000 })
 666→                .resize(DEFAULT_OG_IMAGE_WIDTH, DEFAULT_OG_IMAGE_HEIGHT, { fit: 'cover' })
 667→                .toBuffer();
 668→        } else {
 669→            // Use profile's solid background color if available, otherwise dark fallback
 670→            const solidColor = (typeof bgStyle.background === 'string' && /^#[0-9a-fA-F]{3,8}$/.test(bgStyle.background.trim()))
 671→                ? bgStyle.background.trim()
 672→                : null;
 673→            const gradientSvg = solidColor
 674→                ? `<svg width="${DEFAULT_OG_IMAGE_WIDTH}" height="${DEFAULT_OG_IMAGE_HEIGHT}">
 675→                    <rect width="100%" height="100%" fill="${solidColor}"/>
 676→                </svg>`
 677→                : `<svg width="${DEFAULT_OG_IMAGE_WIDTH}" height="${DEFAULT_OG_IMAGE_HEIGHT}">
 678→                    <defs><linearGradient id="g" x1="0%" y1="0%" x2="100%" y2="100%">
 679→                        <stop offset="0%" stop-color="#1a1a2e"/>
 680→                        <stop offset="100%" stop-color="#16213e"/>
 681→                    </linearGradient></defs>
 682→                    <rect width="100%" height="100%" fill="url(#g)"/>
 683→                </svg>`;
 684→            baseLayer = await sharp(Buffer.from(gradientSvg))
 685→                .resize(DEFAULT_OG_IMAGE_WIDTH, DEFAULT_OG_IMAGE_HEIGHT)
 686→                .png()
 687→                .toBuffer();
 688→        }
 689→
 690→        // ── Dark overlay for text readability ──
 691→        const overlaySvg = `<svg width="${DEFAULT_OG_IMAGE_WIDTH}" height="${DEFAULT_OG_IMAGE_HEIGHT}">
 692→            <rect width="100%" height="100%" fill="black" fill-opacity="0.55"/>
 693→        </svg>`;
 694→        const overlayBuffer = await sharp(Buffer.from(overlaySvg)).png().toBuffer();
 695→
 696→        // ── Circular avatar ──
 697→        let avatarComposite = null;
 698→        const avatarSize = 180;
 699→        const avatarUrl = user.image_url;
 700→        if (avatarUrl) {
 701→            const avatarEval = evaluateShareImageCandidate(avatarUrl);
 702→            if (avatarEval.ok && avatarEval.resolvedUrl) {
 703→                try {
 704→                    const remote = await fetchRemoteImageBuffer(avatarEval.resolvedUrl);
 705→                    const circleMask = Buffer.from(
 706→                        `<svg width="${avatarSize}" height="${avatarSize}">
 707→                            <circle cx="${avatarSize / 2}" cy="${avatarSize / 2}" r="${avatarSize / 2}" fill="white"/>
 708→                        </svg>`
 709→                    );
 710→                    const resizedAvatar = await sharp(remote.buffer, { limitInputPixels: 60_000_000 })
 711→                        .resize(avatarSize, avatarSize, { fit: 'cover' })
 712→                        .png()
 713→                        .toBuffer();
 714→                    const circularAvatar = await sharp(resizedAvatar)
 715→                        .composite([{ input: circleMask, blend: 'dest-in' }])
 716→                        .png()
 717→                        .toBuffer();
 718→                    avatarComposite = circularAvatar;
 719→                } catch { /* skip avatar */ }
 720→            }
 721→        }
 722→
 723→        // ── Compose all layers ──
 724→        const composites = [
 725→            { input: overlayBuffer, top: 0, left: 0 },
 726→        ];
 727→
 728→        if (avatarComposite) {
 729→            const avatarLeft = Math.round((DEFAULT_OG_IMAGE_WIDTH - avatarSize) / 2);
 730→            composites.push({ input: avatarComposite, top: 100, left: avatarLeft });
 731→        }
 732→
 733→        const finalImage = await sharp(baseLayer)
 734→            .composite(composites)
 735→            .jpeg({ quality: 82, mozjpeg: true })
 736→            .toBuffer();
 737→
 738→        res.set('Content-Type', 'image/jpeg');
 739→        res.set('Cache-Control', 'public, max-age=3600');
 740→        return res.send(finalImage);
 741→    } catch (err) {
 742→        console.error('profile share image route error:', err?.message || err);
 743→        return res.redirect(302, DEFAULT_OG_IMAGE_URL);
 744→    }
 745→});
