const CANVAS_GALLERY_LIMIT_DEFAULT = 36;
const CANVAS_GALLERY_LIMIT_MAX = 72;
const CANVAS_GALLERY_HOT_FETCH_LIMIT = 220;
const UNIVERSE_POST_LIMIT_DEFAULT = 200;
