        .insert({
            sender_id: newUserId,
            receiver_id: newUserId,
            journal_id: newJournalId,
            type: 'hottest_post',
            read: false,
        });
    if(newNotifError){
        console.error('hottest new notification error:', newNotifError.message);
    } else {
        console.log('hottest tracker: new #1 post', newJournalId);
    }
}

