};

const normalizeSearchQuery = (query) => {
    if(typeof query !== 'string'){
        return '';
    }

    return query
        .replace(/\s+/g, ' ')
        .trim();
};

const attachUserInteractionFlags = async (journals, userId) => {
    if(!Array.isArray(journals) || journals.length === 0){
        return [];
    }

    if(!userId){
        return journals.map((journal) => ({
            ...journal,
            has_liked: false,
            has_bookmarked: false
        }));
