const sendMetrics = (req, res) => {
    if (!isMetricsAuthorized(req)) {
        return res.status(403).json({ error: 'forbidden' });
    }

    res.set('Cache-Control', 'no-store');
    return res.status(200).json(buildMetricsPayload());
};

